 initWifiP2p()
 }
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 private fun createGroup() {
 Log.d(TAG, "create Group start")

 // 先检查并移除已有群组，移除成功后再创建新群组
 wifiP2pManager.requestGroupInfo(channel) { group ->
 if (group != null) {
 Log.d(TAG, "已有群组存在: ${group.networkName}, 正在移除...")
 wifiP2pManager.removeGroup(channel, object : WifiP2pManager.ActionListener {
 override fun onSuccess() {
 Log.d(TAG, "移除旧群组成功，开始创建新群组")
 // 移除成功后，延迟一小段时间再创建，确保底层状态完全清理
 createButton.postDelayed({
 doCreateGroup()
 }, 500)
 }

 override fun onFailure(reason: Int) {
 Log.e(TAG, "移除旧群组失败: ${reasonToString(reason)}")
 // 即使移除失败，也尝试创建
 doCreateGroup()
 }
 })
 } else {
 Log.d(TAG, "没有旧群组，直接创建新群组")
 doCreateGroup()
 }
 }
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 private fun doCreateGroup() {
 val listener = object : WifiP2pManager.ActionListener {
 override fun onSuccess() {
 Log.d(TAG, "create Group success")
 Toast.makeText(this@MainActivity, "创建群组成功", Toast.LENGTH_SHORT).show()
 }

 override fun onFailure(reason: Int) {
 Log.e(TAG, "create Group fail: ${reasonToString(reason)}")
 Toast.makeText(this@MainActivity, "创建群组失败: ${reasonToString(reason)}", Toast.LENGTH_SHORT).show()
 }
 }

 // 获取设备名并移除空格和特殊字符（Android 16 的 wpa_supplicant 对 SSID 校验更严格）
 val deviceName = utils.getCurrentDeviceName().replace(Regex("[^a-zA-Z0-9_-]"), "")
 val ssid = "DIRECT-WX-" + utils.truncateByBytes(deviceName, 18) + "-" + utils.generateRandomString(3)
 val passphrase = utils.generateRandomString(8)
 Log.d(TAG, "准备创建群组 SSID: $ssid")

 val configBuilder = WifiP2pConfig.Builder()
 .setNetworkName(ssid)
 .setPassphrase(passphrase)

 // Android 10+ 支持设置频段，显式设置为 2.4GHz 以提高兼容性
 if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
 configBuilder.setGroupOperatingBand(WifiP2pConfig.GROUP_OWNER_BAND_2GHZ)
 Log.d(TAG, "已显式设置频段为 2.4GHz")
 }

 val config = configBuilder.build()

 wifiP2pManager.createGroup(channel, config, listener)
 Log.d(TAG, "create Group 请求已发送")
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 private fun removeGroup() {
 wifiP2pManager.requestGroupInfo(channel) { group ->
 if (group != null) {
 Log.d(TAG, "已有群组存在: ${group.networkName}, 正在移除...")
 wifiP2pManager.removeGroup(channel, object : WifiP2pManager.ActionListener {
 override fun onSuccess() { Log.d(TAG, "移除旧群组成功") }
 override fun onFailure(reason: Int) { Log.e(TAG, "移除旧群组失败: ${reasonToString(reason)}") }
 })
 } else {
 Log.d(TAG, "没有群组，不需要移除")
 }
 }
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 override fun onDestroy() {
 super.onDestroy()
 try {
 unregisterReceiver(broadcastReceiver)
 } catch (e: Exception) {
 Log.e(TAG, "注销广播接收器失败: ${e.message}")
 }
 removeGroup()
 }
}
